  id: string;
  title: string;
  description: string;
  icon: string; // Icon name or component
  accent: 'primary' | 'accent' | 'success';
  estimatedTime: string;
  audience: string;
  prerequisites: string[];
  stepCount: number;
}

interface TutorialStep {
  id: string;
  pathId: string;
  stepNumber: number;
  title: string;
  estimatedTime: string;
  whatYouLearn: string[];
  whatYouDo: string[];
  content: React.ReactNode | string; // MDX or component
  moreDetails?: React.ReactNode;
  troubleshooting?: TroubleshootingItem[];
  checkpoint?: CheckpointData;
}

interface TroubleshootingItem {
  problem: string;
  symptoms?: string[];
  solution: string;
  commands?: string[];
}

interface CheckpointData {
  title: string;
  accomplishments: string[];
  nextPreview: string;
}
\`\`\`

